const sendgridApiKey = SECRET_SENDGRID_API_KEY; // Store in Cloudflare Secrets
const stripeApiKey = SECRET_STRIPE_API_KEY; // Store in Cloudflare Secrets

async function sendEmail(to, subject, text) {
    const response = await fetch("https://api.sendgrid.com/v3/mail/send", {
        method: "POST",
        headers: {
            "Authorization": `Bearer ${sendgridApiKey}`,
            "Content-Type": "application/json"
        },
        body: JSON.stringify({
            personalizations: [{ to: [{ email: to }] }],
            from: { email: "your-email@example.com" },
            subject: subject,
            content: [{ type: "text/plain", value: text }]
        })
    });

    if (!response.ok) {
        throw new Error(`SendGrid error: ${response.statusText}`);
    }
}

async function createStripePayment(amount, currency, source) {
    const response = await fetch("https://api.stripe.com/v1/charges", {
        method: "POST",
        headers: {
            "Authorization": `Bearer ${stripeApiKey}`,
            "Content-Type": "application/x-www-form-urlencoded"
        },
        body: new URLSearchParams({
            amount: amount,
            currency: currency,
            source: source
        })
    });

    if (!response.ok) {
        throw new Error(`Stripe error: ${response.statusText}`);
    }

    return await response.json();
}

async function handleRequest(request) {
    const { method, headers } = request;

    if (method !== "POST") {
        return new Response("Method Not Allowed", { status: 405 });
    }

    const contentType = headers.get("Content-Type");
    if (!contentType || !contentType.includes("application/json")) {
        return new Response("Invalid Content-Type", { status: 400 });
    }

    const body = await request.json();
    const { email, subject, message, amount, currency, source } = body;

    // Input validation
    if (!email || !subject || !message || !amount || !currency || !source) {
        return new Response("Missing required fields", { status: 400 });
    }

    try {
        await sendEmail(email, subject, message);
        const paymentResult = await createStripePayment(amount, currency, source);
        return new Response(JSON.stringify({ success: true, paymentResult }), {
            status: 200,
            headers: { "Content-Type": "application/json" }
        });
    } catch (error) {
        return new Response(error.message, { status: 500 });
    }
}

addEventListener("fetch", event => {
    event.respondWith(handleRequest(event.request));
});